import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs';
import { Item, Movement } from '../../core/models';

@Component({
  selector: 'app-audit-log',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './audit-log.component.html',
  styleUrls: ['./audit-log.component.css'],
})
export class AuditLogComponent {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly items = signal<Item[]>([
    { id: '1', sku: 'SR-1001', name: 'Steel Bolt M6', description: '', unit: 'pcs', reorderAt: 100, totalQty: 340 },
    { id: '2', sku: 'SR-1002', name: 'Hex Nut M6', description: '', unit: 'pcs', reorderAt: 100, totalQty: 80 },
    { id: '6', sku: 'SR-1006', name: 'LED Panel 40W', description: '', unit: 'pcs', reorderAt: 20, totalQty: 12 },
  ]);

  readonly movements = signal<Movement[]>([
    { id: 'm3', type: 'TRANSFER', itemId: '2', item: { id: '2', sku: 'SR-1002', name: 'Hex Nut M6' } as Item, fromLocId: 'L1', toLocId: 'L2', fromLocation: { id: 'L1', name: 'Main Warehouse', zone: 'A' }, toLocation: { id: 'L2', name: 'Overflow Depot', zone: 'B' }, qty: 30, note: 'Rebalance', userId: 'u1', user: { email: 'manager@demo' }, createdAt: '2026-07-12T08:40:00Z' },
    { id: 'm2', type: 'OUT', itemId: '2', item: { id: '2', sku: 'SR-1002', name: 'Hex Nut M6' } as Item, fromLocId: 'L1', fromLocation: { id: 'L1', name: 'Main Warehouse', zone: 'A' }, qty: 20, note: 'Line 3 assembly', userId: 'u2', user: { email: 'clerk@demo' }, createdAt: '2026-07-11T14:03:00Z' },
    { id: 'm4', type: 'OUT', itemId: '6', item: { id: '6', sku: 'SR-1006', name: 'LED Panel 40W' } as Item, fromLocId: 'L3', fromLocation: { id: 'L3', name: 'Front Store', zone: 'C' }, qty: 8, note: 'Store fit-out', userId: 'u2', user: { email: 'clerk@demo' }, createdAt: '2026-07-11T10:22:00Z' },
    { id: 'm1', type: 'IN', itemId: '2', item: { id: '2', sku: 'SR-1002', name: 'Hex Nut M6' } as Item, toLocId: 'L1', toLocation: { id: 'L1', name: 'Main Warehouse', zone: 'A' }, qty: 100, note: 'Supplier delivery', userId: 'u1', user: { email: 'manager@demo' }, createdAt: '2026-07-10T09:12:00Z' },
    { id: 'm5', type: 'IN', itemId: '1', item: { id: '1', sku: 'SR-1001', name: 'Steel Bolt M6' } as Item, toLocId: 'L1', toLocation: { id: 'L1', name: 'Main Warehouse', zone: 'A' }, qty: 200, note: 'Bulk order', userId: 'u1', user: { email: 'manager@demo' }, createdAt: '2026-07-09T16:45:00Z' },
  ]);

  private readonly qp = toSignal(
    this.route.queryParamMap.pipe(
      map((p) => ({ itemId: p.get('itemId') ?? '', from: p.get('from') ?? '', to: p.get('to') ?? '' })),
    ),
    { initialValue: { itemId: '', from: '', to: '' } },
  );

  readonly filterItemId = computed(() => this.qp().itemId);
  readonly filterFrom = computed(() => this.qp().from);
  readonly filterTo = computed(() => this.qp().to);

  readonly filtered = computed(() => {
    const { itemId, from, to } = this.qp();
    return this.movements().filter((m) => {
      if (itemId && m.itemId !== itemId) return false;
      const d = m.createdAt.slice(0, 10);
      if (from && d < from) return false;
      if (to && d > to) return false;
      return true;
    });
  });

  constructor(private route: ActivatedRoute, private router: Router) {}

  updateFilter(patch: Record<string, string>): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: patch,
      queryParamsHandling: 'merge',
      replaceUrl: true,
    });
  }

  onItem(event: Event): void {
    this.updateFilter({ itemId: (event.target as HTMLSelectElement).value || '' });
  }
  onFrom(event: Event): void {
    this.updateFilter({ from: (event.target as HTMLInputElement).value || '' });
  }
  onTo(event: Event): void {
    this.updateFilter({ to: (event.target as HTMLInputElement).value || '' });
  }
  clearFilters(): void {
    this.router.navigate([], { relativeTo: this.route, queryParams: {} });
  }
}
